// Cap to most recent N years on each run. Raise to backfill earlier years.
const MAX_YEARS = 3;

const pkg = $input.first().json.result || {};
const resources = pkg.resources || [];

// Multi-line-aware CSV parser. Critical: FIO narratives contain embedded
// newlines inside quoted fields, so naive line-splitting before quote handling
// shifts rows out of alignment. This walks the entire stream and treats
// newlines OUTSIDE of quotes as row separators.
function parseCsv(text) {
  const rows = [];
  let row = [];
  let cur = '';
  let inQuotes = false;
  for (let i = 0; i < text.length; i++) {
    const c = text[i];
    if (inQuotes) {
      if (c === '"') {
        if (text[i + 1] === '"') { cur += '"'; i++; }
        else { inQuotes = false; }
      } else cur += c;
    } else {
      if (c === '"') inQuotes = true;
      else if (c === ',') { row.push(cur); cur = ''; }
      else if (c === '\r') { /* skip; handled by \n */ }
      else if (c === '\n') {
        row.push(cur);
        if (row.length > 1 || row[0] !== '') rows.push(row);
        row = []; cur = '';
      } else cur += c;
    }
  }
  if (cur !== '' || row.length) { row.push(cur); rows.push(row); }
  return rows;
}

function extractYear(name, url) {
  const s = (name || '') + ' ' + (url || '');
  const m = s.match(/(20\d\d)/);
  return m ? parseInt(m[1], 10) : null;
}

function stripBom(s) { return s && s.charCodeAt(0) === 0xFEFF ? s.slice(1) : s; }

const targets = [];
for (const r of resources) {
  const url = (r && r.url) || '';
  if (!/\.csv($|\?)/i.test(url)) continue;
  const name_en = ((r && r.name_translated) || {}).en || '';
  if (/_Name|name_for_public|fio_names|fieldcontactname/i.test(url) || /Name Table/i.test(name_en)) continue;
  if (/2011 - 2015/i.test(name_en)) continue;
  const year = extractYear(name_en, url);
  if (!year) continue;
  targets.push({ url, year, filename: url.split('/').pop(), label: name_en });
}
const byYear = new Map();
for (const t of targets) {
  const cur = byYear.get(t.year);
  if (!cur) { byYear.set(t.year, t); continue; }
  if (/Mark43/i.test(t.label) && !/Mark43/i.test(cur.label)) byYear.set(t.year, t);
}
const sorted = Array.from(byYear.values()).sort((a, b) => b.year - a.year).slice(0, MAX_YEARS);

const out = [];
for (const t of sorted) {
  const text = stripBom(await this.helpers.httpRequest({ method: 'GET', url: t.url, encoding: 'utf8' }));
  const rows = parseCsv(String(text));
  if (rows.length < 2) continue;
  const header = rows[0].map(h => (h || '').trim());
  const idx = (k) => header.indexOf(k);
  const i = {
    fc_num:               idx('fc_num'),
    contact_date:         idx('contact_date'),
    contact_officer:      idx('contact_officer'),
    contact_officer_name: idx('contact_officer_name'),
    supervisor:           idx('supervisor'),
    supervisor_name:      idx('supervisor_name'),
    street:               idx('street'),
    city:                 idx('city'),
    state:                idx('state'),
    zip:                  idx('zip'),
    duration:             idx('duration'),
    circumstance:         idx('circumstance'),
    basis:                idx('basis'),
    vehicle_year:         idx('vehicle_year'),
    vehicle_state:        idx('vehicle_state'),
    vehicle_model:        idx('vehicle_model'),
    vehicle_color:        idx('vehicle_color'),
    vehicle_style:        idx('vehicle_style'),
    vehicle_type:         idx('vehicle_type'),
    key_situations:       idx('key_situations'),
    contact_reason:       idx('contact_reason'),
  };
  for (let li = 1; li < rows.length; li++) {
    const f = rows[li];
    if (!f || f.length === 0) continue;
    const cell = (k) => k >= 0 && f[k] != null ? (String(f[k]).trim() || null) : null;
    const norm = (v) => (v && v !== 'NULL' ? v : null);
    out.push({ json: {
      fc_num:               norm(cell(i.fc_num)),
      contact_date:         norm(cell(i.contact_date)),
      contact_officer:      norm(cell(i.contact_officer)),
      contact_officer_name: norm(cell(i.contact_officer_name)),
      supervisor:           norm(cell(i.supervisor)),
      supervisor_name:      norm(cell(i.supervisor_name)),
      street:               norm(cell(i.street)),
      city:                 norm(cell(i.city)),
      state:                norm(cell(i.state)),
      zip:                  norm(cell(i.zip)),
      duration:             norm(cell(i.duration)),
      circumstance:         norm(cell(i.circumstance)),
      basis:                norm(cell(i.basis)),
      vehicle_year:         norm(cell(i.vehicle_year)),
      vehicle_state:        norm(cell(i.vehicle_state)),
      vehicle_model:        norm(cell(i.vehicle_model)),
      vehicle_color:        norm(cell(i.vehicle_color)),
      vehicle_style:        norm(cell(i.vehicle_style)),
      vehicle_type:         norm(cell(i.vehicle_type)),
      key_situations:       norm(cell(i.key_situations)),
      contact_reason:       norm(cell(i.contact_reason)),
      year:                 t.year,
      source_filename:      t.filename
    }});
  }
}
return out;
